/*Table structure for table `rms_group_detail_student` */

DROP TABLE IF EXISTS `rms_group_detail_student`;

CREATE TABLE `rms_group_detail_student` (
  `gd_id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` int(11) DEFAULT NULL,
  `is_maingrade` tinyint(4) DEFAULT '0',
  `itemType` tinyint(4) DEFAULT '1' COMMENT '1 grade,2 service,3product',
  `startDate` date DEFAULT NULL COMMENT 'សុពលភាពប្រើប្រាស់ ផ្នែក account',
  `endDate` date DEFAULT NULL COMMENT 'សុពលភាពបញ្ចប់ ផ្នែក account',
  `status` tinyint(4) DEFAULT '1',
  `stop_type` tinyint(1) DEFAULT '0' COMMENT '0 = normal,1 stop ,2 suspend,3 = ឆ្លងភូមិសិក្សា,4 graduate,5 NOT PAYMENT',
  `is_pass` int(4) DEFAULT '0' COMMENT '0 = still study in this group , 1 = pass to another group',
  `is_newstudent` tinyint(4) DEFAULT '0' COMMENT '1=new student',
  `note` text,
  `school_option` tinyint(4) DEFAULT '1',
  `academic_year` int(11) DEFAULT '0',
  `degree` int(11) DEFAULT '0' COMMENT 'item id',
  `grade` int(11) DEFAULT '0' COMMENT 'item detail id',
  `session` tinyint(4) DEFAULT '0',
  `is_current` tinyint(4) DEFAULT '0',
  `create_date` datetime DEFAULT NULL,
  `modify_date` datetime DEFAULT NULL,
  `is_setgroup` tinyint(4) DEFAULT '0' COMMENT '1=set group ready',
  `test_restult_id` int(11) DEFAULT '0',
  `entryFrom` tinyint(4) DEFAULT NULL COMMENT '1 crm,2 foundation,3 ក្រុមប្តូរុ,4 payment,5 init,6 test result',
  `feeId` int(11) NOT NULL COMMENT 'តម្លៃពីឆ្នាំសិក្សា',
  `balance` double(10,2) DEFAULT NULL COMMENT 'តម្លៃជំពាក់',
  `isoldBalance` tinyint(4) DEFAULT '0',
  `discount_type` tinyint(4) DEFAULT NULL COMMENT 'discount id',
  `discount_amount` double(10,2) DEFAULT NULL,
  `group_id` int(11) DEFAULT NULL,
  `old_group` int(4) DEFAULT NULL COMMENT 'group ដែលរៀនពីមុន',
  `stu_id` int(11) DEFAULT NULL,
  `user_id` int(11) DEFAULT NULL,
  `partTimeId` int(11) DEFAULT '0' COMMENT 'សម្រាប់សិស្ស CRM/Test/Student ងាយស្រួលបែងចែកសិស្ស Partime ទៅតាមពេលផ្សេងៗ (Ex: 12:00pm-1:30 or 5:30-7:00pm)',
  `oldFeeId` int(11) DEFAULT '0' COMMENT 'feeId ពីថ្នាក់ចាស់',
  PRIMARY KEY (`gd_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3138 DEFAULT CHARSET=utf8 COMMENT='ក្រុម និង និស្សិតចូលគ្នា';

