/*Table structure for table `rms_student` */

DROP TABLE IF EXISTS `rms_student`;

CREATE TABLE `rms_student` (
  `stu_id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` int(11) DEFAULT NULL,
  `customer_type` tinyint(4) DEFAULT '1' COMMENT '1=Student,2=Cutomer,3=Crm,4=Student Test',
  `test_id` int(11) DEFAULT NULL,
  `crm_id` int(11) DEFAULT NULL COMMENT 'connect witth rms_crm',
  `stu_khname` varchar(100) DEFAULT NULL,
  `last_name` varchar(50) DEFAULT NULL,
  `stu_enname` varchar(100) DEFAULT NULL,
  `serial` varchar(200) DEFAULT NULL,
  `stu_code` varchar(40) DEFAULT NULL,
  `sex` tinyint(4) DEFAULT NULL COMMENT '1=m,2=f',
  `calture` int(10) DEFAULT NULL,
  `nationality` varchar(100) DEFAULT NULL,
  `nation` varchar(100) DEFAULT NULL,
  `dob` date DEFAULT NULL,
  `age` int(3) DEFAULT NULL,
  `pob` text,
  `email` varchar(20) DEFAULT NULL,
  `tel` varchar(40) DEFAULT NULL,
  `address` text,
  `home_num` varchar(20) DEFAULT NULL,
  `street_num` varchar(20) DEFAULT NULL,
  `village_name` varchar(100) DEFAULT NULL,
  `commune_name` varchar(100) DEFAULT NULL,
  `district_name` varchar(100) DEFAULT NULL,
  `province_id` int(11) DEFAULT NULL,
  `father_enname` varchar(50) DEFAULT NULL,
  `father_khname` varchar(50) DEFAULT NULL COMMENT 'note used',
  `father_dob` date DEFAULT NULL,
  `father_nation` varchar(50) DEFAULT NULL,
  `father_job` varchar(100) DEFAULT NULL,
  `father_phone` varchar(30) DEFAULT NULL,
  `mother_khname` varchar(120) DEFAULT NULL COMMENT 'note used',
  `mother_enname` varchar(120) DEFAULT NULL,
  `mother_dob` date DEFAULT NULL,
  `mother_nation` varchar(50) DEFAULT NULL,
  `mother_job` varchar(50) DEFAULT NULL,
  `mother_phone` varchar(30) DEFAULT NULL,
  `guardian_first_name` varchar(120) DEFAULT NULL,
  `guardian_enname` varchar(120) DEFAULT NULL,
  `guardian_khname` varchar(120) DEFAULT NULL COMMENT 'not used',
  `guardian_dob` date DEFAULT NULL,
  `guardian_nation` varchar(100) DEFAULT NULL,
  `guardian_document` varchar(100) DEFAULT NULL,
  `guardian_job` int(11) DEFAULT NULL,
  `guardian_tel` varchar(40) DEFAULT NULL,
  `guardian_email` varchar(30) DEFAULT NULL,
  `street` varchar(100) DEFAULT NULL COMMENT 'place of birth',
  `vill_id` int(10) DEFAULT NULL COMMENT 'place of birth',
  `comm_id` int(5) DEFAULT NULL COMMENT 'place of birth',
  `dis_id` int(4) DEFAULT NULL COMMENT 'place of birth',
  `pro_id` int(4) DEFAULT NULL COMMENT 'place of birth',
  `lang_level` varchar(250) DEFAULT NULL COMMENT 'កម្រិតភាសាអង់គ្លេស',
  `from_school` varchar(250) DEFAULT NULL COMMENT 'មកពីសាលា',
  `know_by` varchar(250) DEFAULT NULL COMMENT 'ស្គាល់តាមរយះ',
  `sponser` varchar(250) DEFAULT NULL COMMENT 'អ្នកឧបត្ថម',
  `sponser_phone` varchar(250) DEFAULT NULL COMMENT 'លេខទូរស័ព្ទអ្នកឧបត្ថម',
  `remark` text,
  `password` varchar(200) DEFAULT 'e10adc3949ba59abbe56e057f20f883e',
  `photo` varchar(50) DEFAULT NULL,
  `crm_degree` int(11) DEFAULT NULL,
  `crm_grade` int(11) DEFAULT NULL,
  `crm_partime_id` int(11) DEFAULT NULL,
  `old_grade` varchar(200) DEFAULT NULL COMMENT 'ថ្នាក់ទី ចាស់ពីសាលាផ្សេង',
  `emergency_name` varchar(200) DEFAULT NULL,
  `relationship_to_student` varchar(200) DEFAULT NULL,
  `emergency_tel` varchar(200) DEFAULT NULL,
  `student_option` int(11) DEFAULT NULL COMMENT '1=student,2=working,3=own business',
  `student_status` varchar(200) DEFAULT NULL,
  `status` tinyint(4) DEFAULT '1',
  `modify_date` datetime DEFAULT NULL,
  `create_date` datetime DEFAULT NULL COMMENT 'create fro rec',
  `create_date_stu_test` datetime DEFAULT NULL COMMENT 'date create student test or update student from crm to test',
  `user_id` int(11) DEFAULT NULL,
  `is_studenttest` tinyint(4) DEFAULT '0' COMMENT '0=normal,1=student test',
  `date_bacc` date DEFAULT NULL,
  `province_bacc` int(11) DEFAULT NULL,
  `center_bacc` varchar(70) DEFAULT NULL,
  `room_bacc` varchar(20) DEFAULT NULL,
  `table_bacc` varchar(20) DEFAULT NULL,
  `grade_bacc` varchar(10) DEFAULT NULL,
  `score_bacc` float(5,2) DEFAULT NULL,
  `certificate_bacc` varchar(15) DEFAULT NULL,
  `father_photo` varchar(100) DEFAULT NULL,
  `mother_photo` varchar(100) DEFAULT NULL,
  `guardian_photo` varchar(100) DEFAULT NULL,
  `test_type` tinyint(4) DEFAULT '0',
  `test_setting_id` tinyint(4) DEFAULT '0',
  `primary_phone` tinyint(4) DEFAULT '1',
  `is_setstudentid` tinyint(4) DEFAULT '1',
  `audioTitle` varchar(250) DEFAULT NULL,
  `studentToken` varchar(250) DEFAULT NULL,
  `is_vaccined` tinyint(4) DEFAULT '0',
  `is_covidTested` tinyint(4) DEFAULT '0',
  `dateUpdatedCovidFeature` datetime DEFAULT NULL,
  `setBy` int(11) DEFAULT NULL,
  `lockFromTime` varchar(50) DEFAULT NULL,
  `lockToTime` varchar(50) DEFAULT NULL,
  `dateUpdatedLock` datetime DEFAULT NULL,
  `setLockBy` int(11) DEFAULT '0',
  `isDisbleAccount` tinyint(4) DEFAULT '0',
  `disableDate` datetime DEFAULT NULL,
  `disableValidDate` datetime DEFAULT NULL,
  `academicYearEnroll` int(11) DEFAULT NULL COMMENT 'ឆ្នាំសិក្សាដែលសិស្សចូលរៀនៅសាលា',
  `goHomeType` tinyint(4) DEFAULT '1' COMMENT '1= Go By themselves, 2= Parent Taking,3=school bus...',
  `oldStudentId` int(11) DEFAULT NULL,
  `studentType` int(11) DEFAULT NULL,
  `familyId` int(11) DEFAULT NULL,
  PRIMARY KEY (`stu_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1489 DEFAULT CHARSET=utf8;

