  `dob` date DEFAULT NULL,
  `age` int(3) DEFAULT NULL,
  `pob` text,
  `email` varchar(20) DEFAULT NULL,
  `tel` varchar(40) DEFAULT NULL,
  `address` text,
  `home_num` varchar(20) DEFAULT NULL,
  `street_num` varchar(20) DEFAULT NULL,
