/*Table structure for table `rms_student_payment` */

DROP TABLE IF EXISTS `rms_student_payment`;

CREATE TABLE `rms_student_payment` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` int(11) DEFAULT '1',
  `paystudent_type` int(11) DEFAULT '1' COMMENT '1=new,0 old',
  `revenue_type` int(11) DEFAULT '1' COMMENT '1 student,2 customer',
  `data_from` tinyint(4) DEFAULT NULL COMMENT '1 Old,2Tested,3CRM ,4 new Test,5',
  `student_id` int(11) DEFAULT NULL,
  `receipt_number` varchar(30) DEFAULT NULL,
  `ex_rate` double(10,2) DEFAULT NULL,
  `penalty` double(10,2) DEFAULT NULL COMMENT 'ប្រាក់ពិន័យ',
  `grand_total` double(10,2) DEFAULT NULL COMMENT 'ប្រាក់ត្រូវបង់សរុប',
  `credit_memo` double(10,2) DEFAULT NULL COMMENT 'ប្រាក់នៅសល់ពីមុន',
  `memo_id` int(11) DEFAULT NULL,
  `paid_amount` double(10,2) DEFAULT NULL COMMENT 'ប្រាក់បានបង់',
  `balance_due` double(10,2) DEFAULT NULL COMMENT 'ប្រាក់ដែលនៅជំពាក់រឺនៅសល់',
  `amount_in_khmer` double(10,2) DEFAULT NULL COMMENT 'ប្រាក់ត្រូវបង់សរុបជារៀល',
  `payment_method` tinyint(4) DEFAULT NULL,
  `bank_id` tinyint(4) DEFAULT '0',
  `number` varchar(100) DEFAULT NULL COMMENT 'លេខសែក រឺbank name',
  `group_id` int(11) DEFAULT '0',
  `academic_year` int(11) DEFAULT NULL COMMENT 'is for fee_id',
  `degree_culture` int(11) DEFAULT NULL,
  `degree` int(11) DEFAULT NULL,
  `grade` int(11) DEFAULT NULL,
  `room_id` int(11) DEFAULT NULL,
  `session` int(11) DEFAULT NULL,
  `time` varchar(150) DEFAULT NULL,
  `note` text,
  `user_id` int(11) DEFAULT NULL,
  `col1` int(11) DEFAULT NULL,
  `col2` int(11) DEFAULT NULL,
  `col3` int(11) DEFAULT NULL,
  `is_void` tinyint(4) DEFAULT '0' COMMENT '0=no void , 1= void',
  `void_by` int(11) DEFAULT NULL,
  `void_note` text COMMENT 'អ្នក voide',
  `is_closed` tinyint(4) DEFAULT '0' COMMENT 'បានបិទបញ្ជី',
  `closed_by` int(11) DEFAULT NULL COMMENT 'អ្នកបិទបញ្ជី',
  `create_date` datetime DEFAULT NULL,
  `is_current` tinyint(4) DEFAULT '0',
  `status` tinyint(4) DEFAULT '1',
  `customer_id` int(11) DEFAULT NULL COMMENT 'customer payment id(psis move to new system)',
  `isRead` tinyint(4) DEFAULT '0' COMMENT '0=unread,1=read',
  `readDate` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8;

/*Data for the table `rms_student_payment` */


/*Table structure for table `rms_student_paymentdetail` */

DROP TABLE IF EXISTS `rms_student_paymentdetail`;

CREATE TABLE `rms_student_paymentdetail` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `payment_id` int(11) DEFAULT NULL,
  `itemdetail_id` int(11) DEFAULT NULL,
  `service_type` tinyint(4) DEFAULT '0' COMMENT '1 grade,2 service,3product',
  `feeId` int(11) DEFAULT NULL,
  `payment_term` tinyint(4) DEFAULT NULL,
  `fee` double(10,2) DEFAULT NULL,
  `productCost` double(10,2) DEFAULT NULL COMMENT 'ថ្លៃដើមទំនិញសរុប',
  `qty` double(10,2) DEFAULT NULL,
  `qty_balance` int(11) DEFAULT '0' COMMENT 'ទំនិញជំពាក់',
  `subtotal` double(10,2) DEFAULT NULL,
  `extra_fee` double(10,2) DEFAULT '0.00' COMMENT 'លុយបន្ថែមលើសេវាកម្មឡាន(ពាក់កណ្តល ZoneA & ZoneB)',
  `discount_id` int(11) DEFAULT NULL,
  `discount_type` int(11) DEFAULT NULL,
  `discount_percent` float(6,2) DEFAULT NULL COMMENT 'បញ្ចុះជាភាគរយ',
  `discount_amount` double(10,2) DEFAULT NULL,
  `total_discount` double DEFAULT NULL,
  `totalpayment` double(10,2) DEFAULT NULL COMMENT 'ប្រាក់ត្រូវបង់សរុប',
  `paidamount` double(10,2) DEFAULT NULL COMMENT 'លុយបានបង់តាមសេវានីមួយៗ',
  `is_onepayment` tinyint(4) DEFAULT NULL COMMENT '1=បង់តែមួយដងទេ',
  `previous_startdate` date DEFAULT NULL,
  `previous_enddate` date DEFAULT NULL,
  `start_date` varchar(30) DEFAULT NULL,
  `validate` varchar(30) DEFAULT NULL,
  `is_parent` int(11) DEFAULT '0' COMMENT 'មាននៃថា តមកពី rms_student_paymentdetail id លេខមួយណា (from date)',
  `note` varchar(200) DEFAULT NULL,
  `is_start` varchar(10) DEFAULT '0' COMMENT 'service បង់ចុងក្រោយ,stop use',
  `is_suspend` int(4) DEFAULT '0' COMMENT '0=using,1=suspend,2=stop,stop use',
  `status` tinyint(11) DEFAULT '1',
  `received_date` date DEFAULT NULL COMMENT 'សម្រាប់ផ្នែកស្តុក',
  `remain_date` date DEFAULT NULL COMMENT 'សម្រាប់ផ្នែកស្តុក',
  `stock_user` int(11) DEFAULT '0' COMMENT 'សម្រាប់ផ្នែកស្តុក',
  `stock_note` text COMMENT 'សម្រាប់ផ្នែកស្តុក',
  `academicFeeTermId` int(11) DEFAULT NULL COMMENT 'period of payment',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8;

/*Data for the table `rms_student_paymentdetail` */


