/*View structure for view v_calculate_att */

/*!50001 DROP TABLE IF EXISTS `v_calculate_att` */;
/*!50001 DROP VIEW IF EXISTS `v_calculate_att` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_calculate_att` AS (select `sad`.`subjectId` AS `subjectId`,`sad`.`stu_id` AS `stu_id`,(((20 * count(if((`sad`.`attendence_status` = '2'),`sad`.`attendence_status`,NULL))) + (10 * count(if((`sad`.`attendence_status` = '3'),`sad`.`attendence_status`,NULL)))) + (5 * count(if((`sad`.`attendence_status` = '4'),`sad`.`attendence_status`,NULL)))) AS `totalReduceAtt` from (`rms_student_attendence` `sa` join `rms_student_attendence_detail` `sad` on((`sa`.`id` = `sad`.`attendence_id`))) where ((`sa`.`type` = 1) and (`sad`.`subjectId` > 0) and (`sad`.`attendence_status` <> 1) and (`sad`.`attendence_status` <> 5) and (`sa`.`date_attendence` >= '2023-11-01') and (`sa`.`date_attendence` <= '2023-12-26')) group by `sad`.`stu_id`,`sad`.`subjectId`) */;

/*View structure for view v_getallstudentbygroup */

/*!50001 DROP TABLE IF EXISTS `v_getallstudentbygroup` */;
/*!50001 DROP VIEW IF EXISTS `v_getallstudentbygroup` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_getallstudentbygroup` AS (select `rms_group_detail_student`.`group_id` AS `group_id`,`rms_group_detail_student`.`stu_id` AS `stu_id`,(select `rms_group`.`group_code` from `rms_group` where (`rms_group`.`id` = `rms_group_detail_student`.`group_id`) limit 1) AS `group_code`,(select `rms_student`.`stu_code` from `rms_student` where (`rms_student`.`stu_id` = `rms_group_detail_student`.`stu_id`) limit 1) AS `stu_code`,(select `rms_student`.`stu_khname` from `rms_student` where (`rms_student`.`stu_id` = `rms_group_detail_student`.`stu_id`) limit 1) AS `kh_name`,(select `rms_student`.`stu_enname` from `rms_student` where (`rms_student`.`stu_id` = `rms_group_detail_student`.`stu_id`) limit 1) AS `en_name`,(select `rms_student`.`nationality` from `rms_student` where (`rms_student`.`stu_id` = `rms_group_detail_student`.`stu_id`) limit 1) AS `nation`,(select `rms_student`.`address` from `rms_student` where (`rms_student`.`stu_id` = `rms_group_detail_student`.`stu_id`) limit 1) AS `pob`,(select `rms_student`.`tel` from `rms_student` where (`rms_student`.`stu_id` = `rms_group_detail_student`.`stu_id`) limit 1) AS `tel`,(select (select `rms_view`.`name_kh` from `rms_view` where ((`rms_view`.`type` = 2) and (`rms_view`.`key_code` = `rms_student`.`sex`))) from `rms_student` where (`rms_student`.`stu_id` = `rms_group_detail_student`.`stu_id`) limit 1) AS `sex`,(select `rms_student`.`dob` from `rms_student` where (`rms_student`.`stu_id` = `rms_group_detail_student`.`stu_id`) limit 1) AS `dob`,(select (select `rms_room`.`room_name` from `rms_room` where (`rms_room`.`room_id` = `rms_group`.`room_id`)) from `rms_group` where (`rms_group`.`id` = `rms_group_detail_student`.`group_id`) limit 1) AS `room`,(select (select `rms_view`.`name_en` from `rms_view` where ((`rms_view`.`type` = 4) and (`rms_view`.`key_code` = `rms_group`.`session`)) limit 1) from `rms_group` where (`rms_group`.`id` = `rms_group_detail_student`.`group_id`) limit 1) AS `session`,(select concat(`rms_group`.`from_academic`,'-',`rms_group`.`to_academic`) from `rms_group` where (`rms_group`.`id` = `rms_group_detail_student`.`group_id`) limit 1) AS `academic`,`rms_group_detail_student`.`status` AS `status` from `rms_group_detail_student` where (`rms_group_detail_student`.`status` = 1)) */;

/*View structure for view v_gradingsubjecttotal */

/*!50001 DROP TABLE IF EXISTS `v_gradingsubjecttotal` */;
/*!50001 DROP VIEW IF EXISTS `v_gradingsubjecttotal` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_gradingsubjecttotal` AS (select `v_gradingtotal`.`studentId` AS `studentId`,`v_gradingtotal`.`subjectId` AS `subjectId`,round(sum(`v_gradingtotal`.`totalAvg`),2) AS `totalAvg` from `v_gradingtotal` group by `v_gradingtotal`.`studentId`,`v_gradingtotal`.`subjectId`) */;

/*View structure for view v_gradingtotal */

/*!50001 DROP TABLE IF EXISTS `v_gradingtotal` */;
/*!50001 DROP VIEW IF EXISTS `v_gradingtotal` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_gradingtotal` AS (select `d`.`studentId` AS `studentId`,`d`.`subjectId` AS `subjectId`,`d`.`criteriaId` AS `criteriaId`,`d`.`percentage` AS `percentage`,((avg(`d`.`totalGrading`) * `d`.`percentage`) / 100) AS `totalAvg` from `rms_grading_detail` `d` where (`d`.`gradingTmpId` > 0) group by `d`.`studentId`,`d`.`subjectId`,`d`.`criteriaId`) */;

/*View structure for view v_monthly_semester_avg_lang */

/*!50001 DROP TABLE IF EXISTS `v_monthly_semester_avg_lang` */;
/*!50001 DROP VIEW IF EXISTS `v_monthly_semester_avg_lang` */;

/*!50001 CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_monthly_semester_avg_lang` AS (select `sc`.`id` AS `scoreId`,`sc`.`group_id` AS `groupId`,`scd`.`student_id` AS `studentId`,`sc`.`for_semester` AS `forSemester`,`sc`.`for_academic_year` AS `acadmicYear`,`gsub`.`max_score` AS `subjectMaxScore`,(case when (sum(if((`sub`.`subject_lang` = '1'),`scd`.`score`,0)) > 0) then format((sum(if((`sub`.`subject_lang` = '1'),`scd`.`score`,0)) / (sum(if((`sub`.`subject_lang` = '1'),(`gsub`.`max_score` * `gsub`.`amount_subject`),0)) / `g`.`max_average`)),2) else '0' end) AS `semesterAvgMonthLangKH`,(case when (sum(if((`sub`.`subject_lang` = '2'),`scd`.`score`,0)) > 0) then format((sum(if((`sub`.`subject_lang` = '2'),`scd`.`score`,0)) / (sum(if((`sub`.`subject_lang` = '2'),(`gsub`.`max_score` * `gsub`.`amount_subject`),0)) / `g`.`max_average`)),2) else '0' end) AS `semesterAvgMonthLangEng`,(case when (sum(if((`sub`.`subject_lang` = '3'),`scd`.`score`,0)) > 0) then format((sum(if((`sub`.`subject_lang` = '3'),`scd`.`score`,0)) / (sum(if((`sub`.`subject_lang` = '3'),(`gsub`.`max_score` * `gsub`.`amount_subject`),0)) / `g`.`max_average`)),2) else '0' end) AS `semesterAvgMonthLangCh`,(select group_concat(distinct `subj`.`subject_lang` order by `subj`.`subject_lang` ASC separator ',') from (`rms_subject` `subj` join `rms_group_subject_detail` `gsub1`) where ((`sc`.`group_id` = `gsub1`.`group_id`) and (`subj`.`id` = `gsub1`.`subject_id`) and (`subj`.`status` = 1) and (`subj`.`subject_lang` <> '')) limit 1) AS `subjectLandList` from ((((`rms_score` `sc` join `rms_score_detail` `scd` on((`scd`.`score_id` = `sc`.`id`))) left join `rms_group_subject_detail` `gsub` on(((`gsub`.`group_id` = `sc`.`group_id`) and (`gsub`.`subject_id` = `scd`.`subject_id`)))) join `rms_subject` `sub` on((`sub`.`id` = `scd`.`subject_id`))) join `rms_group` `g` on((`g`.`id` = `sc`.`group_id`))) where ((`sc`.`status` = 1) and (`sc`.`exam_type` = 1) and (`g`.`is_pass` = 2) and (`g`.`status` = 1)) group by `sc`.`id`,`sc`.`group_id`,`sc`.`for_academic_year`,`scd`.`student_id`,`sc`.`exam_type`,`sc`.`for_semester` order by `sc`.`id` desc,`sc`.`group_id`,`scd`.`student_id`) */;

